when.trace:
OpenAI Token Usage















<metadata name="backend-id" value="@(context.Variables.GetValueOrDefault("backendId", "unknown"))" />
<metadata name="route-location" value="@(context.Variables.GetValueOrDefault("routeLocation", "unknown"))" />
<metadata name="route-name" value="@(context.Variables.GetValueOrDefault("routeName", "unknown"))" />
<metadata name="deployment-name" value="@(context.Variables.GetValueOrDefault("deploymentName", "unknown"))" />






<metadata name="is-streaming" value="@(context.Variables.GetValueOrDefault("isStream", false).ToString().ToLower())" />

<metadata name="model" value="@{
    if (!context.Variables.GetValueOrDefault("isStream", false) && context.Variables.ContainsKey("responseBody")) {
        var rb = (JObject)context.Variables["responseBody"];
        var model = rb?["model"]?.ToString();
        if (!string.IsNullOrEmpty(model)) { return model; }
    }
    return context.Variables.GetValueOrDefault("deploymentName", "unknown");
}" />
<metadata name="target-service" value="@{
    if (!context.Variables.GetValueOrDefault("isStream", false) && context.Variables.ContainsKey("responseBody")) {
        var rb = (JObject)context.Variables["responseBody"];
        var obj = rb?["object"]?.ToString();
        if (!string.IsNullOrEmpty(obj)) { return obj; }
    }
    return "chat.completion";
}" />


<metadata name="prompt-tokens" value="@(context.Variables.GetValueOrDefault("promptTokens", 0).ToString())" />
<metadata name="completion-tokens" value="@(context.Variables.GetValueOrDefault("completionTokens", 0).ToString())" />
<metadata name="total-tokens" value="@(context.Variables.GetValueOrDefault("totalTokens", 0).ToString())" />
<metadata name="token-limit-strategy" value="@(context.Variables.GetValueOrDefault("tokenLimitStrategy", "raw_tokens_per_minute"))" />
<metadata name="prompt-tokens-weight" value="@(context.Variables.GetValueOrDefault("promptTokensWeight", 1).ToString())" />
<metadata name="completion-tokens-weight" value="@(context.Variables.GetValueOrDefault("completionTokensWeight", 1).ToString())" />
<metadata name="weighted-tokens-per-minute" value="@(context.Variables.GetValueOrDefault("weightedTokensPerMinute", 0).ToString())" />
<metadata name="weighted-tokens-consumed" value="@(context.Variables.GetValueOrDefault("weightedTokensConsumed", 0).ToString())" />
